table.style:
border-collapse: collapse; 
                              border-spacing: 0; 
                              width: 100%;
                              background:none;
                              color: #555555 !important;
                              border: none !important

td.style:
border-top: 0px; 
                                border-left: 0px;  
                                border-right: 0px; 
                                text-align: right; 
                                padding: 2px 0; 
                                white-space: nowrap; 
                                background: none; 
                                color: #555555 !important;
                                padding: 2px 0px;
                                font-weight: 800 !important;

border-top: 0px; 
                                  border-left: 0px;  
                                  border-right: 0px; 
                                  text-align: right; 
                                  padding: 2px 0; 
                                  white-space: nowrap; 
                                  background: none; 
                                  color: #555555 !important;
                                  padding: 2px 0px;
                                  font-weight: 800 !important;

border-top: 0px; 
                                            border-left: 0px; 
                                            border-right: 0px; 
                                            text-align: right; 
                                            padding: 2px 0; 
                                            white-space: nowrap; 
                                            background: none;
                                            color: #555555 !important;
