tr.t-attf-style:
align-items: center;
border-bottom: 1px solid {{ '#000' if is_parent else '#ccc' }};
font-size: {{ '13px' if is_parent else '13px' }};
font-weight: {{ 'bold' if is_parent else 'normal' }};
line-height: 1.0;

td.t-attf-style:
border-top: 0px; 
                                            border-left: 0px;  
                                            border-right: 0px; 
                                            flex: 1; 
                                            padding-left: {{ level * 15 }}px; 
                                            white-space: nowrap; 
                                            overflow: hidden;
                                            background:none;
                                            color: #555555 !important;
                                            padding-top: {{ padding_top_val }}px;
                                            padding-bottom: 2px;

td.style:
border-top: 0px; 
                                            border-left: 0px;  
                                            border-right: 0px;
                                            min-width: 100px; 
                                            text-align: right; 
                                            white-space: nowrap;
                                            background:none;
                                            color: #555555 !important;
                                            padding-top: {{ padding_top_val }}px;
                                            padding-bottom: 2px;

border-top: 0px; 
                                              border-left: 0px;  
                                              border-right: 0px;
                                              min-width: 100px; 
